from flask import Flask, redirect, url_for, request
import requests

app = Flask(__name__)

# Client ID and secret for OpenID Connect provider (e.g., Google)
client_id = 'your_client_id'
client_secret = 'your_client_secret'

# Authorization endpoint URL
authorization_endpoint = 'https://accounts.google.com/o/oauth2/v2/auth'

# Token endpoint URL
token_endpoint = 'https://oauth2.googleapis.com/token'

@app.route('/login')
def login():
    # Parameters for authorization request
    params = {
        'client_id': client_id,
        'redirect_uri': url_for('callback', _external=True),
        'scope': 'openid',
        'response_type': 'id_token'
    }

    # Send user to authorization endpoint
    return redirect(f'{authorization_endpoint}?{request.args.to_url_query()}')

@app.route('/callback')
def callback():
    code = request.args.get('code')
    if code:
        # Exchange authorization code for ID token
        headers = {'Content-Type': 'application/x-www-form-urlencoded'}
        data = {
            'grant_type': 'authorization_code',
            'code': code,
            'redirect_uri': url_for('callback', _external=True),
            'client_id': client_id,
            'client_secret': client_secret
        }
        response = requests.post(token_endpoint, headers=headers, data=data)
        id_token = response.json()['id_token']
        # Verify ID token (e.g., using Google's public key)
        # For simplicity, this example skips verification
        return f'ID Token: {id_token}'

if __name__ == '__main__':
    app.run(debug=True)